@cocotb.test(timeout_time=200, timeout_unit="ms")
async def cocotb_test_basic_connectivity(dut):
    """
    Basic connectivity test - verify master-to-slave routing

    Test plan:
    3. For each master:
        - Send read to each connected slave
        - Verify address decode routes to correct slave
        - Slave responds with data
        - Verify response reaches master
    """
    tb = Bridge1x4RdTB(dut)
    await tb.setup_clocks_and_reset()

    tb.log.info("=" * 80)
    tb.log.info("Starting basic connectivity test")
    tb.log.info(f"Configuration: 1M x 4S, RD channels")
    tb.log.info("=" * 80)

    # Read connectivity test    tb.log.info(f"Testing master 0 (cpu_rd) read connectivity")
    # Master 0 → Slave 0 (periph_rd)
    test_addr = 0x00000100
    # 32-bit-or-less value (see DEADBEEF comment above for rationale).
    test_data = (0xCAFEBA00 | 0x00)
    tb.log.info(f"  Read: addr=0x{test_addr:08x}, expect_data=0x{test_data:08x}")

    # Master sends read transaction
    await tb.read_transaction(
        master_idx=0,
        address=test_addr,
        txn_id=0
    )

    # Verify AR routed to expected slave only.
    await tb.expect_ar_at_slave(
        slave_idx=0,
        expected_addr=test_addr,
        expected_id=0
    )

    # Slave responds with data
    await tb.slave_respond_read(
        slave_idx=0,
        data=test_data,
        txn_id=0,
        resp=0  # OKAY
    )

    # Verify R response (data + id) returned to originating master.
    await tb.expect_r_at_master(
        master_idx=0,
        expected_id=0,
        expected_data=test_data,
        expected_resp=0
    )

    tb.log.info(f"  Read completed successfully (routing + response verified)")

    # Master 0 → Slave 1 (ddr_rd)
    test_addr = 0x10000100
    # 32-bit-or-less value (see DEADBEEF comment above for rationale).
    test_data = (0xCAFEBA00 | 0x01)
    tb.log.info(f"  Read: addr=0x{test_addr:08x}, expect_data=0x{test_data:08x}")

    # Master sends read transaction
    await tb.read_transaction(
        master_idx=0,
        address=test_addr,
        txn_id=0
    )

    # Verify AR routed to expected slave only.
    await tb.expect_ar_at_slave(
        slave_idx=1,
        expected_addr=test_addr,
        expected_id=0
    )

    # Slave responds with data
    await tb.slave_respond_read(
        slave_idx=1,
        data=test_data,
        txn_id=0,
        resp=0  # OKAY
    )

    # Verify R response (data + id) returned to originating master.
    await tb.expect_r_at_master(
        master_idx=0,
        expected_id=0,
        expected_data=test_data,
        expected_resp=0
    )

    tb.log.info(f"  Read completed successfully (routing + response verified)")

    # Master 0 → Slave 2 (hbm_rd)
    test_addr = 0x50000100
    # 32-bit-or-less value (see DEADBEEF comment above for rationale).
    test_data = (0xCAFEBA00 | 0x02)
    tb.log.info(f"  Read: addr=0x{test_addr:08x}, expect_data=0x{test_data:08x}")

    # Master sends read transaction
    await tb.read_transaction(
        master_idx=0,
        address=test_addr,
        txn_id=0
    )

    # Verify AR routed to expected slave only.
    await tb.expect_ar_at_slave(
        slave_idx=2,
        expected_addr=test_addr,
        expected_id=0
    )

    # Slave responds with data
    await tb.slave_respond_read(
        slave_idx=2,
        data=test_data,
        txn_id=0,
        resp=0  # OKAY
    )

    # Verify R response (data + id) returned to originating master.
    await tb.expect_r_at_master(
        master_idx=0,
        expected_id=0,
        expected_data=test_data,
        expected_resp=0
    )

    tb.log.info(f"  Read completed successfully (routing + response verified)")

    # Master 0 → Slave 3 (apb_periph)
    test_addr = 0x80000100
    # 32-bit-or-less value (see DEADBEEF comment above for rationale).
    test_data = (0xCAFEBA00 | 0x03)
    tb.log.info(f"  Read: addr=0x{test_addr:08x}, expect_data=0x{test_data:08x}")

    # Master sends read transaction
    await tb.read_transaction(
        master_idx=0,
        address=test_addr,
        txn_id=0
    )

    # Verify AR routed to expected slave only.
    await tb.expect_ar_at_slave(
        slave_idx=3,
        expected_addr=test_addr,
        expected_id=0
    )

    # Slave responds with data
    await tb.slave_respond_read(
        slave_idx=3,
        data=test_data,
        txn_id=0,
        resp=0  # OKAY
    )

    # Verify R response (data + id) returned to originating master.
    await tb.expect_r_at_master(
        master_idx=0,
        expected_id=0,
        expected_data=test_data,
        expected_resp=0
    )

    tb.log.info(f"  Read completed successfully (routing + response verified)")

    await ClockCycles(tb.clock, 20)
    tb.log.info("=" * 80)
    tb.log.info("Basic connectivity test PASSED")
    tb.log.info("=" * 80)


@cocotb.test(timeout_time=500, timeout_unit="ms")
async def cocotb_test_address_decode(dut):
    """
    Address decode verification test

    Test plan:
    1. For each master:
        - Send transactions to boundary addresses of each slave region
        - Verify correct slave is selected via address decode
        - Test: base_addr, base_addr + range - 1, out-of-range addresses
    """
    tb = Bridge1x4RdTB(dut)
    await tb.setup_clocks_and_reset()

    tb.log.info("=" * 80)
    tb.log.info("Starting address decode test")
    tb.log.info("=" * 80)    # Master 0: cpu_rd
    tb.log.info(f"Testing master 0 address decode")
    # Slave 0: periph_rd
    # Range: 0x00000000 - 0x0fffffff
    tb.log.info(f"  Slave 0 (periph_rd): 0x00000000-0x0fffffff")    # Test base address
    await tb.read_transaction(0, 0x00000000, txn_id=0)
    await ClockCycles(tb.clock, 3)
    await tb.slave_respond_read(0, 0x22222222, txn_id=0)
    await ClockCycles(tb.clock, 3)

    # Test end address
    await tb.read_transaction(0, 0x0ffffffc, txn_id=0)
    await ClockCycles(tb.clock, 3)
    await tb.slave_respond_read(0, 0x33333333, txn_id=0)
    await ClockCycles(tb.clock, 3)
    # Slave 1: ddr_rd
    # Range: 0x10000000 - 0x4fffffff
    tb.log.info(f"  Slave 1 (ddr_rd): 0x10000000-0x4fffffff")    # Test base address
    await tb.read_transaction(0, 0x10000000, txn_id=0)
    await ClockCycles(tb.clock, 3)
    await tb.slave_respond_read(1, 0x22222223, txn_id=0)
    await ClockCycles(tb.clock, 3)

    # Test end address
    await tb.read_transaction(0, 0x4ffffffc, txn_id=0)
    await ClockCycles(tb.clock, 3)
    await tb.slave_respond_read(1, 0x33333334, txn_id=0)
    await ClockCycles(tb.clock, 3)
    # Slave 2: hbm_rd
    # Range: 0x50000000 - 0x7fffffff
    tb.log.info(f"  Slave 2 (hbm_rd): 0x50000000-0x7fffffff")    # Test base address
    await tb.read_transaction(0, 0x50000000, txn_id=0)
    await ClockCycles(tb.clock, 3)
    await tb.slave_respond_read(2, 0x22222224, txn_id=0)
    await ClockCycles(tb.clock, 3)

    # Test end address
    await tb.read_transaction(0, 0x7ffffffc, txn_id=0)
    await ClockCycles(tb.clock, 3)
    await tb.slave_respond_read(2, 0x33333335, txn_id=0)
    await ClockCycles(tb.clock, 3)
    # Slave 3: apb_periph
    # Range: 0x80000000 - 0x8000ffff
    tb.log.info(f"  Slave 3 (apb_periph): 0x80000000-0x8000ffff")    # Test base address
    await tb.read_transaction(0, 0x80000000, txn_id=0)
    await ClockCycles(tb.clock, 3)
    await tb.slave_respond_read(3, 0x22222225, txn_id=0)
    await ClockCycles(tb.clock, 3)

    # Test end address
    await tb.read_transaction(0, 0x8000fffc, txn_id=0)
    await ClockCycles(tb.clock, 3)
    await tb.slave_respond_read(3, 0x33333336, txn_id=0)
    await ClockCycles(tb.clock, 3)
    await ClockCycles(tb.clock, 20)
    tb.log.info("=" * 80)
    tb.log.info("Address decode test PASSED")
    tb.log.info("=" * 80)

# ============================================================================
# Pytest Wrapper Functions (collected by pytest, call specific cocotb_test_*)
# ============================================================================

def test_bridge_1x4_rd_basic_connectivity(request):
    """Pytest wrapper for basic connectivity test"""

    # Get standard paths
    module, repo_root, tests_dir, log_dir, rtl_dict = get_paths({
        'rtl_bridge': '../../../../rtl/bridge',
        'rtl_common': '../../../../rtl/common',
        'rtl_amba': '../../../../rtl/amba'
    })

    dut_name = "bridge_1x4_rd"

    # Get sources from filelist
    verilog_sources, includes = get_sources_from_filelist(
        repo_root=repo_root,
        filelist_path='projects/components/bridge/rtl/filelists/bridge_1x4_rd.f'
    )

    # Per-test naming follows the q32 canonical pattern
    # (design_dv/q32/tests/macro/test_q32_*.py): test_<dut>_<testcase>
    # plus an optional pytest-xdist worker suffix when running in parallel.
    # `test_name_plus_params` drives EVERY artifact path (log, xml, sim_build,
    # dump.fst) so each parameterised test invocation gets its own
    # directory and outputs.
    worker_id = os.environ.get('PYTEST_XDIST_WORKER', '')
    worker_suffix = f"_{worker_id}" if worker_id else ""
    test_name_plus_params = f"test_{dut_name}_basic_connectivity"
    sim_build_name = f"{test_name_plus_params}{worker_suffix}"

    log_path = os.path.join(log_dir, f'{sim_build_name}.log')
    results_path = os.path.join(log_dir, f'results_{sim_build_name}.xml')
    sim_build = os.path.join(tests_dir, 'local_sim_build', sim_build_name)
    os.makedirs(sim_build, exist_ok=True)
    os.makedirs(log_dir, exist_ok=True)

    # Waveforms via the canonical helper in TBClasses.shared.utilities.
    waves = get_wave_config(sim_build)

    extra_args = ['--assert', '--coverage'] + waves['extra_args']
    extra_env = {
        'COCOTB_LOG_LEVEL': 'INFO',
        'LOG_PATH': log_path,
        'COCOTB_RESULTS_FILE': results_path,
        **waves['extra_env'],
    }

    run(
        python_search=[tests_dir],
        verilog_sources=verilog_sources,
        includes=includes,
        toplevel=dut_name,
        module=module,
        testcase="cocotb_test_basic_connectivity",
        sim_build=sim_build,
        waves=False,            # cocotb-test compile flags handled via extra_args
        extra_args=extra_args,
        plus_args=waves['sim_args'],
        extra_env=extra_env
    )


